                    <button
                      key={m.id}
                      onClick={() => setMode(m.id as GameMode)}
                      className={`rounded-lg border px-2 py-2 ${mode === m.id ? "border-sky-400 bg-sky-500/20 text-sky-200" : "border-slate-600 text-slate-300 hover:bg-slate-800/40"}`}
                    >
