      'bg-slate-100 text-slate-700 ring-1 ring-inset ring-slate-200 dark:bg-slate-800 dark:text-slate-200 dark:ring-slate-700',
    role: 'status',
    ariaLive: 'polite',
    defaultTitle: 'No matches yet',
